const puppeteer = require('puppeteer');

let _browser = null;
async function getBrowser() {
  if (!_browser || !_browser.isConnected()) {
    _browser = await puppeteer.launch({
      headless: 'new',
      args: ['--no-sandbox', '--disable-setuid-sandbox', '--disable-dev-shm-usage', '--disable-gpu'],
    });
  }
  return _browser;
}

// POST /ifood/verificar-localizador
// Body: { localizador: "12345678" }
// Retorna: { ok: true, nomeCliente: "TAIANE" }
app.post('/ifood/verificar-localizador', async (req, res) => {
  const { localizador } = req.body;
  if (!localizador || localizador.length !== 8) return res.status(400).json({ ok: false, error: 'Localizador deve ter 8 digitos' });
  try {
    const apiUrl = 'https://merchant-api.ifood.com.br/marketplace-delivery-handshake/order-available/localizers/' + localizador;
    const resp = await axios.get(apiUrl, { timeout: 10000, headers: { 'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36', 'Accept': 'application/json, text/plain, */*', 'Origin': 'https://confirmacao-entrega-propria.ifood.com.br', 'Referer': 'https://confirmacao-entrega-propria.ifood.com.br/' } });
    const data = resp.data;
    const nomeCliente = data.customerName || data.customer_name || data.name || null;
    const numeroPedidoIfood = data.shortId || data.short_id || data.orderNumber || null;
    if (!nomeCliente && !numeroPedidoIfood) return res.status(404).json({ ok: false, error: 'Localizador nao encontrado ou invalido' });
    return res.json({ ok: true, nomeCliente, numeroPedidoIfood });
  } catch (err) {
    if (err.response && err.response.status === 404) return res.status(404).json({ ok: false, error: 'Localizador nao encontrado ou invalido' });
    if (err.response && err.response.status === 422) return res.status(422).json({ ok: false, error: 'Localizador invalido ou pedido ja entregue' });
    console.error('[iFood] verificar erro:', err.message);
    return res.status(500).json({ ok: false, error: 'Erro ao verificar localizador: ' + err.message });
  }
});

// POST /ifood/confirmar-entrega
// Body: { localizador: "12345678", codigoCliente: "1234" }
// Retorna: { ok: true } ou { ok: false, erro: "..." }
app.post('/ifood/confirmar-entrega', async (req, res) => {
  const { localizador, codigoCliente } = req.body;
  if (!localizador || localizador.length !== 8) return res.status(400).json({ ok: false, erro: 'Localizador deve ter 8 digitos' });
  if (!codigoCliente || codigoCliente.length !== 4) return res.status(400).json({ ok: false, erro: 'Codigo do cliente deve ter 4 digitos' });
  let page;
  try {
    const browser = await getBrowser();
    page = await browser.newPage();
    await page.goto('https://confirmacao-entrega-propria.ifood.com.br/numero-pedido', { waitUntil: 'networkidle2', timeout: 30000 });
    // Passo 1: digita localizador
    const inputs1 = await page.$$('input');
    const digits1 = localizador.split('');
    for (let i = 0; i < 8 && i < inputs1.length; i++) {
      await inputs1[i].click();
      await inputs1[i].type(digits1[i]);
      await page.waitForTimeout(100);
    }
    await page.evaluate(() => {
      const btns = Array.from(document.querySelectorAll('button'));
      const btn = btns.find(b => b.textContent.includes('Continuar') || b.type === 'submit');
      if (btn) btn.click();
    });
    await page.waitForNavigation({ waitUntil: 'networkidle2', timeout: 15000 });
    // Passo 2: digita codigo do cliente (4 digitos)
    const inputs2 = await page.$$('input');
    const digits2 = codigoCliente.split('');
    for (let i = 0; i < 4 && i < inputs2.length; i++) {
      await inputs2[i].click();
      await inputs2[i].type(digits2[i]);
      await page.waitForTimeout(100);
    }
    await page.evaluate(() => {
      const btns = Array.from(document.querySelectorAll('button'));
      const btn = btns.find(b => b.textContent.includes('Confirmar') || b.type === 'submit');
      if (btn) btn.click();
    });
    await page.waitForTimeout(3000);
    // Verifica sucesso
    const sucesso = await page.evaluate(() => {
      const body = document.body.textContent;
      return body.includes('entrega confirmada') || body.includes('Entrega confirmada') || body.includes('sucesso') || body.includes('confirmado');
    });
    await page.close();
    if (sucesso) return res.json({ ok: true });
    return res.status(400).json({ ok: false, erro: 'Codigo incorreto ou pedido nao encontrado' });
  } catch (err) {
    if (page) await page.close().catch(() => {});
    console.error('[iFood bot] confirmar erro:', err.message);
    return res.status(500).json({ ok: false, erro: 'Erro ao confirmar entrega: ' + err.message });
  }
});

